import{_ as n,o as l,c as s,ag as r}from"./chunks/framework.-Wrcbzkw.js";const g=JSON.parse('{"title":"大模型基础概念","description":"","frontmatter":{},"headers":[],"relativePath":"LLM/基础知识/基本概念.md","filePath":"LLM/基础知识/基本概念.md","lastUpdated":1777981213000}'),e={name:"LLM/基础知识/基本概念.md"};function i(t,a,o,h,d,p){return l(),s("div",null,[...a[0]||(a[0]=[r(`<h1 id="大模型基础概念" tabindex="-1">大模型基础概念 <a class="header-anchor" href="#大模型基础概念" aria-label="Permalink to &quot;大模型基础概念&quot;">​</a></h1><h2 id="什么是大语言模型" tabindex="-1">什么是大语言模型 <a class="header-anchor" href="#什么是大语言模型" aria-label="Permalink to &quot;什么是大语言模型&quot;">​</a></h2><p>大语言模型（Large Language Model, LLM）是一种基于深度学习的人工智能模型，通过学习海量文本数据来理解和生成人类语言。</p><h3 id="核心特点" tabindex="-1">核心特点 <a class="header-anchor" href="#核心特点" aria-label="Permalink to &quot;核心特点&quot;">​</a></h3><ol><li><strong>海量参数</strong>：通常拥有数十亿甚至数万亿个参数</li><li><strong>上下文理解</strong>：能够理解长文本上下文</li><li><strong>多任务能力</strong>：可以执行多种语言任务，如问答、翻译、摘要等</li><li><strong>涌现能力</strong>：随着模型规模增大，会出现一些意想不到的能力</li></ol><h2 id="大模型发展历程" tabindex="-1">大模型发展历程 <a class="header-anchor" href="#大模型发展历程" aria-label="Permalink to &quot;大模型发展历程&quot;">​</a></h2><h3 id="早期阶段" tabindex="-1">早期阶段 <a class="header-anchor" href="#早期阶段" aria-label="Permalink to &quot;早期阶段&quot;">​</a></h3><ul><li><strong>ELMo</strong> (2018): 基于双向LSTM的预训练模型</li><li><strong>GPT-1</strong> (2018): OpenAI发布的首个GPT模型</li><li><strong>BERT</strong> (2018): Google发布的双向预训练模型</li></ul><h3 id="快速发展" tabindex="-1">快速发展 <a class="header-anchor" href="#快速发展" aria-label="Permalink to &quot;快速发展&quot;">​</a></h3><ul><li><strong>GPT-2</strong> (2019): 更大规模的GPT模型，具备零样本学习能力</li><li><strong>GPT-3</strong> (2020): 1750亿参数，展现强大的Few-shot学习能力</li><li><strong>PaLM</strong> (2022): Google发布的5400亿参数模型</li></ul><h3 id="最新进展" tabindex="-1">最新进展 <a class="header-anchor" href="#最新进展" aria-label="Permalink to &quot;最新进展&quot;">​</a></h3><ul><li><strong>GPT-4</strong> (2023): 支持多模态输入，能力大幅提升</li><li><strong>LLaMA</strong> (2023): Meta开源的大模型系列</li><li><strong>Qwen</strong> (2023): 阿里云发布的通义千问模型</li></ul><h2 id="大模型架构" tabindex="-1">大模型架构 <a class="header-anchor" href="#大模型架构" aria-label="Permalink to &quot;大模型架构&quot;">​</a></h2><h3 id="transformer架构" tabindex="-1">Transformer架构 <a class="header-anchor" href="#transformer架构" aria-label="Permalink to &quot;Transformer架构&quot;">​</a></h3><p>Transformer是大模型的核心架构，由Vaswani等人在2017年提出。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Transformer架构组成：</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Encoder                             │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │  Multi-Head Attention + Feed Forward Network    │   │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                    Decoder                             │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │ Masked Multi-Head Attention                     │   │</span></span>
<span class="line"><span>│  │ + Encoder-Decoder Attention                     │   │</span></span>
<span class="line"><span>│  │ + Feed Forward Network                          │   │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="核心组件" tabindex="-1">核心组件 <a class="header-anchor" href="#核心组件" aria-label="Permalink to &quot;核心组件&quot;">​</a></h3><ol><li><strong>多头注意力机制</strong>：允许模型同时关注输入序列的不同部分</li><li><strong>位置编码</strong>：为模型提供序列顺序信息</li><li><strong>前馈神经网络</strong>：对每个位置进行独立的非线性变换</li></ol><h2 id="训练流程" tabindex="-1">训练流程 <a class="header-anchor" href="#训练流程" aria-label="Permalink to &quot;训练流程&quot;">​</a></h2><h3 id="预训练阶段" tabindex="-1">预训练阶段 <a class="header-anchor" href="#预训练阶段" aria-label="Permalink to &quot;预训练阶段&quot;">​</a></h3><ul><li><strong>目标</strong>：学习通用语言知识</li><li><strong>数据</strong>：海量无标注文本</li><li><strong>任务</strong>：预测下一个词（自回归语言建模）</li></ul><h3 id="微调阶段" tabindex="-1">微调阶段 <a class="header-anchor" href="#微调阶段" aria-label="Permalink to &quot;微调阶段&quot;">​</a></h3><ul><li><strong>目标</strong>：适应特定任务</li><li><strong>方法</strong>：在标注数据集上进行微调</li><li><strong>技术</strong>：Prompt Tuning、LoRA等高效微调技术</li></ul><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to &quot;应用场景&quot;">​</a></h2><h3 id="自然语言处理" tabindex="-1">自然语言处理 <a class="header-anchor" href="#自然语言处理" aria-label="Permalink to &quot;自然语言处理&quot;">​</a></h3><ul><li>文本生成</li><li>机器翻译</li><li>情感分析</li><li>问答系统</li></ul><h3 id="代码开发" tabindex="-1">代码开发 <a class="header-anchor" href="#代码开发" aria-label="Permalink to &quot;代码开发&quot;">​</a></h3><ul><li>代码生成</li><li>代码补全</li><li>代码解释</li></ul><h3 id="创意内容" tabindex="-1">创意内容 <a class="header-anchor" href="#创意内容" aria-label="Permalink to &quot;创意内容&quot;">​</a></h3><ul><li>写作辅助</li><li>剧本创作</li><li>诗歌生成</li></ul><h2 id="挑战与展望" tabindex="-1">挑战与展望 <a class="header-anchor" href="#挑战与展望" aria-label="Permalink to &quot;挑战与展望&quot;">​</a></h2><h3 id="当前挑战" tabindex="-1">当前挑战 <a class="header-anchor" href="#当前挑战" aria-label="Permalink to &quot;当前挑战&quot;">​</a></h3><ol><li><strong>计算资源需求大</strong>：训练成本高昂</li><li><strong>上下文长度有限</strong>：理解长文本能力受限</li><li><strong>幻觉问题</strong>：可能生成虚假信息</li><li><strong>偏见与安全</strong>：存在潜在的伦理问题</li></ol><h3 id="未来方向" tabindex="-1">未来方向 <a class="header-anchor" href="#未来方向" aria-label="Permalink to &quot;未来方向&quot;">​</a></h3><ol><li><strong>高效推理</strong>：降低部署成本</li><li><strong>多模态融合</strong>：结合视觉、语音等多种模态</li><li><strong>领域专业化</strong>：针对特定领域优化</li><li><strong>可解释性</strong>：提高模型决策的透明度</li></ol>`,35)])])}const u=n(e,[["render",i]]);export{g as __pageData,u as default};
